#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[1001];
        scanf("%s", S);
        int N = strlen(S);
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                int k = 0;
                int flag = 1;
                while (k <= (j - i) / 2) {
                    if (S[i + k] != S[j - k]) {
                        flag = 0;
                        break;
                    }
                    k++;
                }
                if (flag) count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

