code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            String S = scanner.next();
            int N = S.length();
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i; j < N; j++) {
                    int k = 0;
                    int flag = 1;
                    while (k <= (j - i) / 2) {
                        if (S.charAt(i + k) != S.charAt(j - k)) {
                            flag = 0;
                            break;
                        }
                        k++;
                    }
                    if (flag) count++;
                }
            }
            System.out.println(count);
        }
    }
}

